INSERT INTO pack_prices (pack_id, amount, currency, product_id_ios, product_id_android, is_active)
VALUES
  ('renaissance_mind',        2.99, 'USD', 'com.mindscrolling.pack.renaissance_mind',        'com.mindscrolling.pack.renaissance_mind',        true),
  ('classical_foundations',   2.99, 'USD', 'com.mindscrolling.pack.classical_foundations',   'com.mindscrolling.pack.classical_foundations',   true),
  ('modern_human_condition',  2.99, 'USD', 'com.mindscrolling.pack.modern_human_condition',  'com.mindscrolling.pack.modern_human_condition',  true)
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, tags) VALUES
(gen_random_uuid(), 'Nature is the source of all true knowledge. She has her own logic, her own laws, she has no effect without cause nor invention without necessity.', 'Leonardo da Vinci', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'learning', 'wisdom']),
(gen_random_uuid(), 'The noblest pleasure is the joy of understanding.', 'Leonardo da Vinci', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Simplicity is the ultimate sophistication.', 'Leonardo da Vinci', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'focus', 'self_improvement']),
(gen_random_uuid(), 'I have been impressed with the urgency of doing. Knowing is not enough; we must apply. Being willing is not enough; we must do.', 'Leonardo da Vinci', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['discipline', 'motivation', 'self_improvement']),
(gen_random_uuid(), 'Obstacles cannot crush me. Every obstacle yields to stern resolve. He who is fixed to a star does not change his mind.', 'Leonardo da Vinci', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Nothing strengthens authority so much as silence.', 'Leonardo da Vinci', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'Poor is the pupil who does not surpass his master.', 'Leonardo da Vinci', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['learning', 'self_improvement', 'curiosity']),
(gen_random_uuid(), 'The eye, which is called the window of the soul, is the principal means by which the central sense can appreciate the infinite works of nature.', 'Leonardo da Vinci', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'existence']),
(gen_random_uuid(), 'In rivers, the water that you touch is the last of what has passed and the first of that which comes; so with present time.', 'Leonardo da Vinci', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['reflection', 'mindfulness', 'existence']),
(gen_random_uuid(), 'He who loves practice without theory is like the sailor who boards ship without a rudder and compass and never knows where he may cast.', 'Leonardo da Vinci', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'creativity', 'wisdom']),
(gen_random_uuid(), 'It is better to be feared than loved, if you cannot be both.', 'Niccolò Machiavelli', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'The first method for estimating the intelligence of a ruler is to look at the men he has around him.', 'Niccolò Machiavelli', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'Never was anything great achieved without danger.', 'Niccolò Machiavelli', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'inner_strength', 'motivation']),
(gen_random_uuid(), 'Where the willingness is great, the difficulties cannot be great.', 'Niccolò Machiavelli', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['discipline', 'motivation', 'inner_strength']),
(gen_random_uuid(), 'Men are driven by two principal impulses, either by love or by fear.', 'Niccolò Machiavelli', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'existence', 'reflection']),
(gen_random_uuid(), 'The end justifies the means only when the means do not destroy the end.', 'Niccolò Machiavelli', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'meaning', 'reflection']),
(gen_random_uuid(), 'One who deceives will always find those who allow themselves to be deceived.', 'Niccolò Machiavelli', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'There is no avoiding war; it can only be postponed to the advantage of others.', 'Niccolò Machiavelli', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'inner_strength', 'wisdom']),
(gen_random_uuid(), 'I speak of the ordinary run of man, for of those who are extraordinary there is no accounting.', 'Niccolò Machiavelli', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Whosoever desires constant success must change his conduct with the times.', 'Niccolò Machiavelli', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['self_improvement', 'motivation', 'wisdom']),
(gen_random_uuid(), 'Every man should be his own physician. We ought to assist and not to force nature.', 'Michel de Montaigne', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'self_improvement', 'reflection']),
(gen_random_uuid(), 'The greatest thing in the world is to know how to belong to oneself.', 'Michel de Montaigne', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['self_love', 'wisdom', 'reflection']),
(gen_random_uuid(), 'On the highest throne in the world, we still sit only on our own bottom.', 'Michel de Montaigne', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Every man bears the whole stamp of the human condition.', 'Michel de Montaigne', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'reflection', 'meaning']),
(gen_random_uuid(), 'Not being able to govern events, I govern myself.', 'Michel de Montaigne', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['inner_strength', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'Lend yourself to others, but give yourself to yourself.', 'Michel de Montaigne', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['self_love', 'wisdom', 'reflection']),
(gen_random_uuid(), 'A man who fears suffering is already suffering from what he fears.', 'Michel de Montaigne', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'It is not death that a man should fear, but he should fear never beginning to live.', 'Michel de Montaigne', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'existence', 'meaning']),
(gen_random_uuid(), 'The soul which has no fixed purpose in life is lost; to be everywhere is to be nowhere.', 'Michel de Montaigne', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['focus', 'meaning', 'wisdom']),
(gen_random_uuid(), 'I study myself more than any other subject; it is my metaphysics, it is my physics.', 'Michel de Montaigne', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['reflection', 'curiosity', 'self_improvement']),
(gen_random_uuid(), 'In the works of men as in those of nature, it is the intention which gives the character to the whole.', 'Francis Bacon', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'meaning', 'reflection']),
(gen_random_uuid(), 'Knowledge is power.', 'Francis Bacon', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'learning', 'self_improvement']),
(gen_random_uuid(), 'Wonder is the seed of knowledge.', 'Francis Bacon', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'existence']),
(gen_random_uuid(), 'Natural abilities are like natural plants; they need pruning by study.', 'Francis Bacon', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['creativity', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Reading maketh a full man; conference a ready man; and writing an exact man.', 'Francis Bacon', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['learning', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'He that hath wife and children hath given hostages to fortune; for they are impediments to great enterprises, either of virtue or mischief.', 'Francis Bacon', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'creativity', 'existence']),
(gen_random_uuid(), 'Prosperity is not without many fears and distastes; and adversity is not without comforts and hopes.', 'Francis Bacon', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['creativity', 'wisdom', 'curiosity']),
(gen_random_uuid(), 'Nam et ipsa scientia potestas est — for knowledge itself is power.', 'Francis Bacon', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['learning', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Discretion of speech is more than eloquence; and to speak agreeably to him with whom we deal is more than to speak in good words or in good order.', 'Francis Bacon', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'If a man will begin with certainties, he shall end in doubts; but if he will be content to begin with doubts, he shall end in certainties.', 'Francis Bacon', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'calm', 'reflection']),
(gen_random_uuid(), 'The monuments of wit survive the monuments of power.', 'Francis Bacon', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'courage', 'wisdom']),
(gen_random_uuid(), 'The joys of parents are secret, and so are their griefs and fears.', 'Francis Bacon', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['reflection', 'existence', 'meaning']),
(gen_random_uuid(), 'We are the masters of our fate; the captains of our souls.', 'Thomas More', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['inner_strength', 'courage', 'meaning']),
(gen_random_uuid(), 'The man who lives without folly is not so wise as he thinks.', 'Erasmus', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'Give light, and the darkness will disappear of itself.', 'Erasmus', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'meaning', 'courage']),
(gen_random_uuid(), 'By a Carpenter mankind was made, and only by that Carpenter can mankind be remade.', 'Erasmus', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'The most disadvantageous peace is better than the most just war.', 'Erasmus', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'calm']),
(gen_random_uuid(), 'Your library is your paradise.', 'Erasmus', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['learning', 'curiosity', 'wisdom']),
(gen_random_uuid(), 'He who lets the world, or his own portion of it, choose his plan of life for him has no need of any other faculty than the ape-like one of imitation.', 'Thomas More', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['self_improvement', 'wisdom', 'meaning']),
(gen_random_uuid(), 'We cannot get grace from gadgets.', 'Thomas More', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'meaning']),
(gen_random_uuid(), 'The things, good Lord, that we pray for, give us the grace to labour for.', 'Thomas More', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['discipline', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'I die the king''s good servant, but God''s first.', 'Thomas More', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Go up a little to come down a little. This is how I have lived all my life.', 'Petrarch', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'To be able to say how much love, is love but little.', 'Petrarch', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Who is so brave that he has no fear at all? Only the man who feels no affection.', 'Petrarch', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Five enemies of peace inhabit with us: avarice, ambition, envy, anger, and pride.', 'Petrarch', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'What else is all history, but the praise of Rome?', 'Petrarch', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'learning', 'curiosity']),
(gen_random_uuid(), 'Sameness is the mother of disgust, variety the cure.', 'Petrarch', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'self_improvement']),
(gen_random_uuid(), 'Books have led some to learning and others to madness, when they swallow more than they can digest.', 'Petrarch', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'learning', 'reflection']),
(gen_random_uuid(), 'We are as much as we see. Faith is sight and knowledge.', 'Marsilio Ficino', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'The soul in the body is like light in a lantern; it illuminates the visible world.', 'Marsilio Ficino', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Love is the attraction of beauty; beauty is the splendor of goodness.', 'Marsilio Ficino', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'creativity', 'meaning']),
(gen_random_uuid(), 'The mind of man is immortal by nature and divine by origin.', 'Marsilio Ficino', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'We ought to esteem it of the greatest importance that the fictions which children first hear should be adapted in the most perfect manner to the promotion of virtue.', 'Giovanni Pico della Mirandola', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'learning', 'self_improvement']),
(gen_random_uuid(), 'We have made you neither of heavenly nor of earthly stuff, so that you can shape yourself into whatever form you choose.', 'Giovanni Pico della Mirandola', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'meaning', 'self_improvement']),
(gen_random_uuid(), 'Man is rightly called a great miracle, a living creature worthy of admiration.', 'Giovanni Pico della Mirandola', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'curiosity', 'meaning']),
(gen_random_uuid(), 'Strive to be all you can be, to realize your own unique potential.', 'Giovanni Pico della Mirandola', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['self_improvement', 'motivation', 'meaning']),
(gen_random_uuid(), 'I do not want to force nature; I study it and follow it.', 'Galileo Galilei', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'learning']),
(gen_random_uuid(), 'You cannot teach a man anything; you can only help him find it within himself.', 'Galileo Galilei', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'learning', 'self_improvement']),
(gen_random_uuid(), 'All truths are easy to understand once they are discovered; the point is to discover them.', 'Galileo Galilei', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'learning']),
(gen_random_uuid(), 'The sun, with all those planets revolving around it, can still ripen a bunch of grapes as if it had nothing else in the universe to do.', 'Galileo Galilei', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'courage', 'curiosity']),
(gen_random_uuid(), 'Philosophy is written in this grand book, the universe, which stands continually open to our gaze, but cannot be understood unless one first learns its language.', 'Galileo Galilei', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'existence']),
(gen_random_uuid(), 'Measure what can be measured, and make measurable what cannot be.', 'Galileo Galilei', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'learning', 'discipline']),
(gen_random_uuid(), 'He who looks the higher is the more highly distinguished.', 'Giordano Bruno', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'The universe is one, infinite, immobile. The absolute potential is one, the act is one, the form or soul is one, the matter or body is one.', 'Giordano Bruno', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'wisdom', 'curiosity']),
(gen_random_uuid(), 'It is proof of a narrow mind to confine knowledge to one specialty.', 'Leon Battista Alberti', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'learning', 'wisdom']),
(gen_random_uuid(), 'A man can do all things if he but wills them.', 'Leon Battista Alberti', 'philosophy', 'en', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['motivation', 'inner_strength', 'self_improvement']),
(gen_random_uuid(), 'Beauty is a harmony of all the parts, in whatsoever subject it appears.', 'Leon Battista Alberti', 'philosophy', 'en', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['creativity', 'wisdom', 'existence']),
(gen_random_uuid(), 'I am a courtier: grace, beauty, and dignity are my concern.', 'Baldassare Castiglione', 'philosophy', 'en', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'creativity', 'self_improvement']),
(gen_random_uuid(), 'Do not be proud of things that are not your own virtue; only what belongs to yourself can truly ornament you.', 'Baldassare Castiglione', 'philosophy', 'en', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement'])
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, tags) VALUES
(gen_random_uuid(), 'El aprendizaje nunca agota la mente.', 'Leonardo da Vinci', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'learning', 'wisdom']),
(gen_random_uuid(), 'La experiencia nunca yerra; solo yerran vuestros juicios al prometerse de ella efectos ajenos a los que están en su poder.', 'Leonardo da Vinci', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'learning']),
(gen_random_uuid(), 'El que no castiga el mal, ordena que se haga.', 'Leonardo da Vinci', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'La pintura es poesía que se ve y no se oye, y la poesía es pintura que se oye pero no se ve.', 'Leonardo da Vinci', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['creativity', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Quien piensa poco se equivoca mucho.', 'Leonardo da Vinci', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'Nada fortalece tanto la autoridad como el silencio.', 'Leonardo da Vinci', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'calm']),
(gen_random_uuid(), 'La naturaleza es la fuente de todo conocimiento verdadero. Tiene su propia lógica, sus propias leyes; no tiene efecto sin causa ni invención sin necesidad.', 'Leonardo da Vinci', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'learning']),
(gen_random_uuid(), 'La sencillez es la máxima sofisticación.', 'Leonardo da Vinci', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'focus', 'reflection']),
(gen_random_uuid(), 'El hombre que no tiene experiencia de las cosas más duras de la vida, no ha vivido lo suficiente.', 'Michel de Montaigne', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'resilience', 'existence']),
(gen_random_uuid(), 'Hay una verdad más real que cualquier otra verdad posible: yo mismo existo.', 'Michel de Montaigne', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'self_love', 'reflection']),
(gen_random_uuid(), 'Lo más grande del mundo es saber pertenecerse a uno mismo.', 'Michel de Montaigne', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['self_love', 'wisdom', 'inner_strength']),
(gen_random_uuid(), 'La ignorancia que se conoce a sí misma, que se juzga y se condena, no es ignorancia completa.', 'Michel de Montaigne', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'El hombre que teme el sufrimiento ya sufre de lo que teme.', 'Michel de Montaigne', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'Me estudio a mí mismo más que a cualquier otro tema; es mi metafísica, es mi física.', 'Michel de Montaigne', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['reflection', 'curiosity', 'self_improvement']),
(gen_random_uuid(), 'Presta tu atención a los demás, pero dáte a ti mismo.', 'Michel de Montaigne', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['self_love', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Cada hombre lleva consigo la forma entera de la condición humana.', 'Michel de Montaigne', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'reflection', 'meaning']),
(gen_random_uuid(), 'Es mejor ser llorado por tu nacimiento que reído por tu muerte.', 'Niccolò Machiavelli', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'courage', 'reflection']),
(gen_random_uuid(), 'El que desea o pretende engañar siempre encontrará quien se deje engañar.', 'Niccolò Machiavelli', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Los hombres no hacen el bien sino por necesidad; cuando tienen libertad de elegir y pueden actuar con toda libertad, todo se convierte en confusión y desorden.', 'Niccolò Machiavelli', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Nunca hubo nada grande que no estuviera acompañado de peligro.', 'Niccolò Machiavelli', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'inner_strength', 'motivation']),
(gen_random_uuid(), 'Quien cambia su conducta con los tiempos, ese prospera.', 'Niccolò Machiavelli', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['self_improvement', 'wisdom', 'motivation']),
(gen_random_uuid(), 'La guerra no se evita; solo se aplaza en ventaja de los otros.', 'Niccolò Machiavelli', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'wisdom', 'inner_strength']),
(gen_random_uuid(), 'El conocimiento es poder.', 'Francis Bacon', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'learning', 'self_improvement']),
(gen_random_uuid(), 'La lectura hace al hombre completo; la conversación, ágil; y el escribir, preciso.', 'Francis Bacon', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['learning', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'La verdad es tan difícil de decir que a veces necesita de la ficción para hacerse plausible.', 'Francis Bacon', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'creativity', 'existence']),
(gen_random_uuid(), 'El silencio es el sueño que nutre la sabiduría.', 'Francis Bacon', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'calm', 'reflection']),
(gen_random_uuid(), 'No hay ninguna belleza excelente que no tenga alguna rareza en la proporción.', 'Francis Bacon', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['creativity', 'wisdom', 'curiosity']),
(gen_random_uuid(), 'Aquellos que son descubridores pobres piensan que no hay tierra cuando solo ven el mar.', 'Francis Bacon', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'courage', 'wisdom']),
(gen_random_uuid(), 'Toda belleza tiene algo de raro.', 'Francis Bacon', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['creativity', 'curiosity', 'wisdom']),
(gen_random_uuid(), 'La esperanza es un buen desayuno, pero una mala cena.', 'Francis Bacon', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'meaning']),
(gen_random_uuid(), 'Muero siendo buen servidor del rey, pero antes de Dios.', 'Thomas More', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Pide a Dios las cosas que necesitas y ten la gracia de trabajar para conseguirlas.', 'Thomas More', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['discipline', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'No podemos obtener la gracia de los artilugios.', 'Thomas More', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'meaning']),
(gen_random_uuid(), 'La virtud más grande es la que se practica sin esperanza de recompensa.', 'Thomas More', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'Dale luz, y la oscuridad desaparecerá por sí misma.', 'Erasmus', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'meaning', 'courage']),
(gen_random_uuid(), 'Tu biblioteca es tu paraíso.', 'Erasmus', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['learning', 'curiosity', 'wisdom']),
(gen_random_uuid(), 'La paz más desventajosa es mejor que la guerra más justa.', 'Erasmus', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'calm']),
(gen_random_uuid(), 'El hombre que vive sin locura no es tan sabio como cree.', 'Erasmus', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'La unidad en lo necesario, libertad en lo dudoso, caridad en todo.', 'Erasmus', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'meaning', 'reflection']),
(gen_random_uuid(), 'Rara vez cohabitan la gran belleza y la gran virtud.', 'Petrarch', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Cinco enemigos de la paz habitan en nosotros: la avaricia, la ambición, la envidia, la ira y el orgullo.', 'Petrarch', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'Los libros han llevado a algunos al saber y a otros a la locura, cuando ingieren más de lo que pueden digerir.', 'Petrarch', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'learning', 'reflection']),
(gen_random_uuid(), 'La saciedad es madre del hastío; la variedad es su cura.', 'Petrarch', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'self_improvement']),
(gen_random_uuid(), 'Sube un poco para bajar un poco. Así he vivido toda mi vida.', 'Petrarch', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'El alma que no tiene un propósito fijo se pierde; estar en todas partes es no estar en ninguna.', 'Petrarch', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['focus', 'meaning', 'wisdom']),
(gen_random_uuid(), 'El amor es la atracción de la belleza; la belleza es el esplendor de la bondad.', 'Marsilio Ficino', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'creativity', 'meaning']),
(gen_random_uuid(), 'La mente del hombre es inmortal por naturaleza y divina por origen.', 'Marsilio Ficino', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'El alma en el cuerpo es como la luz en un farol; ilumina el mundo visible.', 'Marsilio Ficino', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Somos tanto como vemos. La fe es visión y conocimiento.', 'Marsilio Ficino', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'Os hemos hecho sin materia celeste ni terrena, para que podáis plasmaros en la forma que prefiráis.', 'Giovanni Pico della Mirandola', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'meaning', 'self_improvement']),
(gen_random_uuid(), 'El hombre es llamado con razón un gran milagro, un ser vivo digno de admiración.', 'Giovanni Pico della Mirandola', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'curiosity', 'meaning']),
(gen_random_uuid(), 'Esfuérzate por ser todo lo que puedes ser, para realizar tu único y propio potencial.', 'Giovanni Pico della Mirandola', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['self_improvement', 'motivation', 'meaning']),
(gen_random_uuid(), 'No deseo forzar la naturaleza; la estudio y la sigo.', 'Galileo Galilei', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'learning']),
(gen_random_uuid(), 'No puedes enseñar nada a nadie; solo puedes ayudarle a que lo encuentre dentro de sí mismo.', 'Galileo Galilei', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'learning', 'self_improvement']),
(gen_random_uuid(), 'Todas las verdades son fáciles de entender una vez descubiertas; el asunto es descubrirlas.', 'Galileo Galilei', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'learning']),
(gen_random_uuid(), 'En cuestiones de ciencia, la autoridad de mil no vale el humilde razonamiento de un individuo.', 'Galileo Galilei', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'courage', 'curiosity']),
(gen_random_uuid(), 'Mide lo que se puede medir y haz medible lo que no se puede.', 'Galileo Galilei', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'learning', 'discipline']),
(gen_random_uuid(), 'La Biblia enseña el camino al cielo, no el camino de los cielos.', 'Galileo Galilei', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'existence']),
(gen_random_uuid(), 'El que mira más alto es el que más se distingue.', 'Giordano Bruno', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['courage', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'El universo es uno, infinito, inmóvil. El potencial absoluto es uno; el acto es uno; la forma es una.', 'Giordano Bruno', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'wisdom', 'curiosity']),
(gen_random_uuid(), 'Es prueba de mente estrecha confinar el conocimiento a una sola especialidad.', 'Leon Battista Alberti', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'learning', 'wisdom']),
(gen_random_uuid(), 'Un hombre puede hacer todo lo que quiera si así lo desea.', 'Leon Battista Alberti', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['motivation', 'inner_strength', 'self_improvement']),
(gen_random_uuid(), 'La belleza es una armonía de todas las partes, en cualquier sujeto donde aparezca.', 'Leon Battista Alberti', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['creativity', 'wisdom', 'existence']),
(gen_random_uuid(), 'No te enorgullezcas de lo que no es virtud propia; solo lo que te pertenece puede adornarte verdaderamente.', 'Baldassare Castiglione', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'La gracia verdadera no se aprende; nace del alma que ha comprendido su propio ser.', 'Baldassare Castiglione', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'self_love', 'reflection']),
(gen_random_uuid(), 'La virtud es la única nobleza verdadera.', 'Lorenzo de'' Medici', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Quien no valora la vida no merece vivirla.', 'Leonardo da Vinci', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'El conocimiento sin práctica es como un libro que nunca se abre.', 'Francis Bacon', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['learning', 'discipline', 'wisdom']),
(gen_random_uuid(), 'La filosofía es el amor a la sabiduría y la sabiduría es el amor a Dios.', 'Marsilio Ficino', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'meaning', 'existence']),
(gen_random_uuid(), 'En el río, el agua que tocas es la última de lo que ha pasado y la primera de lo que viene; así es el tiempo presente.', 'Leonardo da Vinci', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['reflection', 'mindfulness', 'existence']),
(gen_random_uuid(), 'La duda es el origen del conocimiento.', 'Michel de Montaigne', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'learning']),
(gen_random_uuid(), 'La razón es el mayor don que Dios nos ha dado; usarla es honrarle.', 'Erasmus', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'learning', 'meaning']),
(gen_random_uuid(), 'El que no mira hacia adelante se queda atrás.', 'Petrarch', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['motivation', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'Quien sabe esperar, todo lo alcanza.', 'Giordano Bruno', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['resilience', 'inner_strength', 'wisdom'])
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, tags) VALUES
(gen_random_uuid(), 'The shortest and surest way to live with honour in the world is to be in reality what we would appear to be.', 'Socrates', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'An honest man is always a child.', 'Socrates', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'reflection']),
(gen_random_uuid(), 'The hour of departure has arrived, and we go our ways — I to die, and you to live. Which is better only God knows.', 'Socrates', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'mindfulness']),
(gen_random_uuid(), 'The secret of change is to focus all of your energy not on fighting the old, but on building the new.', 'Socrates', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['motivation', 'self_improvement', 'focus']),
(gen_random_uuid(), 'To find yourself, think for yourself.', 'Socrates', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'He who is not contented with what he has, would not be contented with what he would like to have.', 'Socrates', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'gratitude']),
(gen_random_uuid(), 'False words are not only evil in themselves, but they infect the soul with evil.', 'Socrates', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'Employ your time in improving yourself by other men''s writings so that you shall come easily by what others have labored hard for.', 'Socrates', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'Be slow to fall into friendship; but when thou art in, continue firm and constant.', 'Socrates', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'learning']),
(gen_random_uuid(), 'From the deepest desires often come the deadliest hate.', 'Socrates', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'curiosity']),
(gen_random_uuid(), 'The direction in which education starts a man will determine his future life.', 'Plato', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['courage', 'wisdom', 'existence']),
(gen_random_uuid(), 'At the touch of love, everyone becomes a poet.', 'Plato', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['creativity', 'meaning', 'wisdom']),
(gen_random_uuid(), 'No one ever teaches well who wants to teach, or governs well who wants to govern.', 'Plato', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'He who commits injustice is ever made more wretched than he who suffers it.', 'Plato', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['motivation', 'inner_strength', 'self_improvement']),
(gen_random_uuid(), 'Education is teaching our children to desire the right things.', 'Plato', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'Ignorance, the root and stem of every evil.', 'Plato', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'learning', 'existence']),
(gen_random_uuid(), 'The beginning is the most important part of any work.', 'Plato', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'motivation', 'wisdom']),
(gen_random_uuid(), 'The soul of man is immortal and imperishable.', 'Plato', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'learning']),
(gen_random_uuid(), 'Self-conquest is the greatest of all victories.', 'Plato', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['courage', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'The first and greatest victory is to conquer yourself; to be conquered by yourself is of all things the most shameful and vile.', 'Plato', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'All human beings by nature desire to know.', 'Aristotle', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'Those who educate children well are more to be honored than they who produce them.', 'Aristotle', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'resilience', 'wisdom']),
(gen_random_uuid(), 'It is the mark of an educated mind to be able to entertain a thought without accepting it.', 'Aristotle', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'reflection']),
(gen_random_uuid(), 'To perceive is to suffer.', 'Aristotle', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'self_improvement', 'meaning']),
(gen_random_uuid(), 'Wishing to be friends is quick work, but friendship is a slow-ripening fruit.', 'Aristotle', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'Without friends, no one would choose to live, though he had all other goods.', 'Aristotle', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['creativity', 'wisdom', 'existence']),
(gen_random_uuid(), 'Quality is not an act; it is a habit.', 'Aristotle', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'self_improvement', 'focus']),
(gen_random_uuid(), 'Probable impossibilities are to be preferred to improbable possibilities.', 'Aristotle', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'In poverty and other misfortunes of life, true friends are a sure refuge.', 'Aristotle', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Excellence is an art won by training and habituation.', 'Aristotle', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'existence']),
(gen_random_uuid(), 'To live happily is an inward power of the soul.', 'Cicero', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'A room without books is like a body without a soul.', 'Cicero', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Gratitude is not only the greatest of virtues, but the parent of all others.', 'Cicero', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['gratitude', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Any man can make mistakes, but only an idiot persists in his error.', 'Cicero', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'self_improvement', 'reflection']),
(gen_random_uuid(), 'The higher we are placed, the more humbly we should walk.', 'Cicero', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'inner_strength']),
(gen_random_uuid(), 'We must not say every mistake is a foolish one.', 'Cicero', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'The study of philosophy is not that we may know what men have thought, but what the truth of things is.', 'Cicero', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'learning']),
(gen_random_uuid(), 'Never go to excess, but let moderation be your guide.', 'Cicero', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'discipline', 'reflection']),
(gen_random_uuid(), 'It is not enough to acquire wisdom; we must put it to use.', 'Cicero', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'discipline', 'self_improvement']),
(gen_random_uuid(), 'The wise are instructed by reason, average minds by experience, the stupid by necessity.', 'Cicero', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'learning', 'reflection']),
(gen_random_uuid(), 'You are what your deep, driving desire is.', 'Heraclitus', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['meaning', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'No man ever steps in the same river twice, for it''s not the same river and he''s not the same man.', 'Heraclitus', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'The path up and down are one and the same.', 'Heraclitus', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Big results require big ambitions.', 'Heraclitus', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['motivation', 'courage', 'wisdom']),
(gen_random_uuid(), 'If you do not expect the unexpected, you will not find it.', 'Heraclitus', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Eyes are more exact witnesses than ears.', 'Heraclitus', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'learning']),
(gen_random_uuid(), 'Do not do to others what angers you if done to you by others.', 'Isocrates', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Seek not the good in external things; seek it in yourselves.', 'Epictetus', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'self_improvement']),
(gen_random_uuid(), 'Do not seek to have things that happen as you wish, but wish for the things that happen to be as they are, and you will have a tranquil flow of life.', 'Epicurus', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['calm', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Of all the things which wisdom provides for living one''s life, the greatest is the possession of friendship.', 'Epicurus', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'meaning', 'reflection']),
(gen_random_uuid(), 'Accustom yourself to believing that death is nothing to us, for good and evil imply awareness, and death is the privation of all awareness.', 'Epicurus', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'gratitude', 'calm']),
(gen_random_uuid(), 'Death is nothing to us, since when we exist, death is not yet present, and when death is present, then we do not exist.', 'Epicurus', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Not what we have but what we enjoy constitutes our abundance.', 'Epicurus', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'The whole world is my native land.', 'Diogenes', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'freedom']),
(gen_random_uuid(), 'Of what use is a philosopher who doesn''t hurt anybody''s feelings?', 'Diogenes', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'courage', 'reflection']),
(gen_random_uuid(), 'It is not that I am mad, it is only that my head is different from yours.', 'Diogenes', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'We have two ears and one tongue so that we would listen more and talk less.', 'Diogenes', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'The great thieves lead away the little thief.', 'Diogenes', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'learning', 'meaning']),
(gen_random_uuid(), 'Number is the ruler of forms and ideas, and the cause of gods and demons.', 'Pythagoras', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'curiosity']),
(gen_random_uuid(), 'Rest satisfied with doing well, and leave others to talk of you as they please.', 'Pythagoras', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'self_improvement']),
(gen_random_uuid(), 'Above the cloud with its shadow is the star with its light.', 'Pythagoras', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'courage', 'meaning']),
(gen_random_uuid(), 'Choose always the way that seems the best, however rough it may be.', 'Pythagoras', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['courage', 'discipline', 'wisdom']),
(gen_random_uuid(), 'As long as man continues to be the ruthless destroyer of lower living beings he will never know health or peace.', 'Pythagoras', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Nothing great happens without enthusiasm.', 'Democritus', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['motivation', 'courage', 'wisdom']),
(gen_random_uuid(), 'Happiness resides not in possessions and not in gold; happiness dwells in the soul.', 'Democritus', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'The wrongdoer is more unfortunate than the man wronged.', 'Democritus', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Do not try to understand everything, because some things are not meant for you to understand.', 'Democritus', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'calm']),
(gen_random_uuid(), 'By desiring little, a poor man makes himself rich.', 'Democritus', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'gratitude', 'reflection']),
(gen_random_uuid(), 'The water from the sea is the purest, but also the most undrinkable.', 'Thales', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'reflection']),
(gen_random_uuid(), 'Know thyself.', 'Thales', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'The most difficult thing in life is to know yourself.', 'Thales', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'There is nothing so easy but that it becomes difficult when you do it with reluctance.', 'Plutarch', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'The mind is not a vessel to be filled, but a fire to be kindled.', 'Plutarch', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['curiosity', 'learning', 'wisdom']),
(gen_random_uuid(), 'Know how to listen, and you will profit even from those who talk badly.', 'Plutarch', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'learning', 'reflection']),
(gen_random_uuid(), 'Character is simply habit long continued.', 'Plutarch', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'An imbalance between rich and poor is the oldest and most fatal ailment of all republics.', 'Plutarch', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['inner_strength', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'Fate leads the willing and drags along the reluctant.', 'Plutarch', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'courage', 'existence']),
(gen_random_uuid(), 'Not in the clamor of the crowded street, nor in the shouts and plaudits of the throng, but in ourselves are triumph and defeat.', 'Plutarch', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['inner_strength', 'wisdom', 'reflection']),
(gen_random_uuid(), 'To do nothing is sometimes a good remedy.', 'Hippocrates', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'calm', 'reflection']),
(gen_random_uuid(), 'If someone wishes for good health, one must ask whether they are ready to do away with the reasons for their illness.', 'Hippocrates', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'meaning', 'existence']),
(gen_random_uuid(), 'Life is short, art long, opportunity fleeting, experience treacherous, judgment difficult.', 'Hippocrates', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement'])
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, tags) VALUES
(gen_random_uuid(), 'Una vida sin examen no merece ser vivida.', 'Socrates', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Solo sé que no sé nada.', 'Socrates', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'reflection']),
(gen_random_uuid(), 'El principio de la sabiduría es el asombro.', 'Socrates', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'learning']),
(gen_random_uuid(), 'Para encontrarte a ti mismo, piensa por ti mismo.', 'Socrates', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'Desconfía del exceso de trabajo; deja espacio para la contemplación.', 'Socrates', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'mindfulness']),
(gen_random_uuid(), 'Las palabras falsas no solo son malas en sí mismas, sino que infectan el alma con el mal.', 'Socrates', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'El que no está satisfecho con lo que tiene tampoco lo estaría con lo que quisiera tener.', 'Socrates', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'gratitude']),
(gen_random_uuid(), 'La educación es encender una llama, no llenar un recipiente.', 'Socrates', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'curiosity', 'wisdom']),
(gen_random_uuid(), 'Lo que no sabes te puede hacer libre; lo que te niegas a aprender te ata.', 'Socrates', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'self_improvement']),
(gen_random_uuid(), 'Ocupad vuestra mente en mejorarse leyendo a los hombres ilustres; así adquiriréis fácilmente lo que otros han logrado con dificultad.', 'Socrates', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'Podemos perdonar fácilmente a un niño que teme a la oscuridad; la verdadera tragedia es cuando los hombres temen a la luz.', 'Plato', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['courage', 'wisdom', 'existence']),
(gen_random_uuid(), 'La ignorancia es la raíz y el tallo de todo mal.', 'Plato', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'learning', 'existence']),
(gen_random_uuid(), 'Las buenas acciones nos fortalecen e inspiran buenas acciones en otros.', 'Plato', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['motivation', 'inner_strength', 'self_improvement']),
(gen_random_uuid(), 'Nadie enseña bien quien quiere enseñar ni gobierna bien quien quiere gobernar.', 'Plato', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'La medida del hombre es lo que hace con el poder.', 'Plato', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'El comienzo es la parte más importante de cualquier trabajo.', 'Plato', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'motivation', 'wisdom']),
(gen_random_uuid(), 'La opinión es el medio entre el conocimiento y la ignorancia.', 'Plato', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'learning']),
(gen_random_uuid(), 'Estamos doblemente armados si luchamos con fe.', 'Plato', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['courage', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Al contacto del amor, todo el mundo se convierte en poeta.', 'Plato', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['creativity', 'meaning', 'wisdom']),
(gen_random_uuid(), 'El exceso en todo es un defecto.', 'Plato', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'Somos lo que hacemos repetidamente. La excelencia, por tanto, no es un acto sino un hábito.', 'Aristotle', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'Las raíces de la educación son amargas, pero el fruto es dulce.', 'Aristotle', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'resilience', 'wisdom']),
(gen_random_uuid(), 'Es señal de mente cultivada poder entretenerse con una idea sin necesariamente aceptarla.', 'Aristotle', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'reflection']),
(gen_random_uuid(), 'La felicidad depende de nosotros mismos.', 'Aristotle', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'self_improvement', 'meaning']),
(gen_random_uuid(), 'Conocerte a ti mismo es el comienzo de toda sabiduría.', 'Aristotle', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'Ninguna gran mente ha existido sin un toque de locura.', 'Aristotle', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['creativity', 'wisdom', 'existence']),
(gen_random_uuid(), 'El todo es más que la suma de sus partes.', 'Aristotle', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'El amigo de todos no es amigo de nadie.', 'Aristotle', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'La virtud es una disposición a elegir el término medio entre los extremos.', 'Aristotle', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'discipline', 'self_improvement']),
(gen_random_uuid(), 'En todas las cosas de la naturaleza hay algo de maravilloso.', 'Aristotle', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'existence']),
(gen_random_uuid(), 'Vivir felizmente es una facultad interna del alma.', 'Cicero', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Una habitación sin libros es como un cuerpo sin alma.', 'Cicero', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'wisdom', 'meaning']),
(gen_random_uuid(), 'La gratitud no es solo la mayor de las virtudes, sino la madre de todas ellas.', 'Cicero', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['gratitude', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Cualquier hombre puede cometer errores, pero solo un necio persiste en su error.', 'Cicero', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'self_improvement', 'reflection']),
(gen_random_uuid(), 'Cuanto más alto estemos, más humildemente debemos caminar.', 'Cicero', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'inner_strength']),
(gen_random_uuid(), 'No es suficiente adquirir sabiduría; hay que usarla.', 'Cicero', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'discipline', 'self_improvement']),
(gen_random_uuid(), 'Los sabios son instruidos por la razón; las mentes ordinarias, por la experiencia; los necios, por la necesidad.', 'Cicero', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'learning', 'reflection']),
(gen_random_uuid(), 'Que la moderación sea tu guía; jamás te excedas.', 'Cicero', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'discipline', 'reflection']),
(gen_random_uuid(), 'No podrás cruzar el mismo río dos veces, porque siempre fluyen aguas nuevas.', 'Heraclitus', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'El carácter es el destino.', 'Heraclitus', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Si no esperas lo inesperado, no lo encontrarás.', 'Heraclitus', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Mucho aprendizaje no enseña a comprender.', 'Heraclitus', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'learning']),
(gen_random_uuid(), 'Eres aquello que es tu deseo más profundo y más vivo.', 'Heraclitus', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['meaning', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'La guerra es el padre de todas las cosas.', 'Heraclitus', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['existence', 'wisdom', 'courage']),
(gen_random_uuid(), 'No busques el bien en las cosas externas; búscalo en ti mismo.', 'Epictetus', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'self_improvement']),
(gen_random_uuid(), 'No desees que todo suceda como quieres; desea que las cosas sucedan como son, y así tendrás tranquilidad.', 'Epicurus', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['calm', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Entre los dones que la sabiduría otorga para vivir una vida plena, el mayor es la amistad.', 'Epicurus', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'meaning', 'reflection']),
(gen_random_uuid(), 'No malogres lo que tienes por desear lo que no tienes.', 'Epicurus', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'gratitude', 'calm']),
(gen_random_uuid(), 'La muerte no es nada para nosotros; cuando existimos, la muerte no está presente; cuando la muerte está presente, entonces nosotros no existimos.', 'Epicurus', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'El arte de vivir bien y el arte de morir bien son uno solo.', 'Epicurus', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'El mundo entero es mi tierra natal.', 'Diogenes', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'Tenemos dos orejas y una lengua para escuchar más y hablar menos.', 'Diogenes', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'La base de todo Estado es la educación de su juventud.', 'Diogenes', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'learning', 'meaning']),
(gen_random_uuid(), 'No es que yo esté loco; simplemente mi cabeza es diferente a la tuya.', 'Diogenes', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'El número es el soberano de las formas e ideas.', 'Pythagoras', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'curiosity']),
(gen_random_uuid(), 'Conténtate con hacer bien; deja que los demás hablen de ti como gusten.', 'Pythagoras', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'self_improvement']),
(gen_random_uuid(), 'Elige siempre el camino que parezca mejor, aunque sea difícil.', 'Pythagoras', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['courage', 'discipline', 'wisdom']),
(gen_random_uuid(), 'Por encima de la nube con su sombra está la estrella con su luz.', 'Pythagoras', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'courage', 'meaning']),
(gen_random_uuid(), 'La felicidad no reside en las posesiones ni en el oro; la felicidad mora en el alma.', 'Democritus', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Nada grande sucede sin entusiasmo.', 'Democritus', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['motivation', 'courage', 'wisdom']),
(gen_random_uuid(), 'El que hace el mal es más desafortunado que el que lo padece.', 'Democritus', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Deseando poco, el pobre se hace rico.', 'Democritus', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'gratitude', 'reflection']),
(gen_random_uuid(), 'No intentes comprender todo, porque hay cosas que no están destinadas a que las entiendas.', 'Democritus', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'calm']),
(gen_random_uuid(), 'Conócete a ti mismo.', 'Thales', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'Lo más difícil de la vida es conocerse a uno mismo.', 'Thales', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'No hay nada tan fácil que se vuelva difícil cuando se hace a regañadientes.', 'Plutarch', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'La mente no es un recipiente que hay que llenar, sino un fuego que hay que encender.', 'Plutarch', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['curiosity', 'learning', 'wisdom']),
(gen_random_uuid(), 'Aprende a escuchar y sacarás provecho incluso de los que hablan mal.', 'Plutarch', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'learning', 'reflection']),
(gen_random_uuid(), 'El carácter no es sino el hábito mantenido largo tiempo.', 'Plutarch', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'Lo que logremos interiormente cambiará la realidad exterior.', 'Plutarch', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['inner_strength', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'El destino conduce al que quiere ir y arrastra al que no quiere.', 'Plutarch', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'courage', 'existence']),
(gen_random_uuid(), 'No en el clamor de la calle ni en los aplausos de la multitud, sino en nosotros mismos están el triunfo y la derrota.', 'Plutarch', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['inner_strength', 'wisdom', 'reflection']),
(gen_random_uuid(), 'El exceso en todo es contrario a la naturaleza.', 'Hippocrates', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'self_improvement']),
(gen_random_uuid(), 'Dondequiera que el arte de la medicina sea amado, también hay amor a la humanidad.', 'Hippocrates', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'meaning', 'existence']),
(gen_random_uuid(), 'A veces, lo mejor que se puede hacer es no hacer nada.', 'Hippocrates', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'calm', 'reflection'])
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, tags) VALUES
(gen_random_uuid(), 'The smallest act in the most limited circumstances bears the seed of the same boundlessness, because one deed and sometimes one word suffice to change every constellation.', 'Hannah Arendt', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'meaning', 'existence']),
(gen_random_uuid(), 'Storytelling reveals meaning without committing the error of defining it.', 'Hannah Arendt', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'meaning', 'creativity']),
(gen_random_uuid(), 'Clichés, stock phrases, adherence to conventional codes of expression have the socially recognized function of protecting us against reality.', 'Hannah Arendt', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'The most radical revolutionary will become a conservative the day after the revolution.', 'Hannah Arendt', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Power corresponds to the human ability not just to act but to act in concert.', 'Hannah Arendt', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'meaning', 'courage']),
(gen_random_uuid(), 'The greatest enemy of authority, therefore, is contempt, and the surest way to undermine it is laughter.', 'Hannah Arendt', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Forgiveness is the only reaction which does not merely re-act but acts anew and unexpectedly.', 'Hannah Arendt', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'No one has the right to obey.', 'Hannah Arendt', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'wisdom', 'existence']),
(gen_random_uuid(), 'To be free is actually to begin something new.', 'Hannah Arendt', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'meaning', 'self_improvement']),
(gen_random_uuid(), 'We are all the same, that is, human, in such a way that nobody is ever the same as anyone else who ever lived.', 'Hannah Arendt', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'One is not born, but rather becomes, a woman.', 'Simone de Beauvoir', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'I am too intelligent, too demanding, and too resourceful for anyone to be able to take charge of me entirely.', 'Simone de Beauvoir', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['self_love', 'inner_strength', 'wisdom']),
(gen_random_uuid(), 'Representation of the world, like the world itself, is the work of men; they describe it from their own point of view.', 'Simone de Beauvoir', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['motivation', 'discipline', 'self_improvement']),
(gen_random_uuid(), 'In itself, homosexuality is as limiting as heterosexuality: the ideal should be to be capable of loving a woman or a man.', 'Simone de Beauvoir', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'It is in the knowledge of the genuine conditions of our life that we must draw our strength to live and our reasons for acting.', 'Simone de Beauvoir', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'It is impossible to regard woman simply as a sexual being. She is a human being and must be treated as such.', 'Simone de Beauvoir', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'wisdom', 'existence']),
(gen_random_uuid(), 'Woman is not born: she is made. In the making, qualities attributed to men are suppressed in her, and she is shaped for a role.', 'Simone de Beauvoir', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'existence', 'wisdom']),
(gen_random_uuid(), 'To will oneself free is also to will others free.', 'Simone de Beauvoir', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'meaning', 'wisdom']),
(gen_random_uuid(), 'Between the ages of twenty and forty we are engaged in the process of discovering who we are.', 'Simone de Beauvoir', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['reflection', 'self_improvement', 'existence']),
(gen_random_uuid(), 'Everything has been figured out, except how to live.', 'Simone de Beauvoir', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'Between stimulus and response there is a space. In that space is our power to choose our response.', 'Viktor Frankl', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'Life is never made unbearable by circumstances, but only by lack of meaning and purpose.', 'Viktor Frankl', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'resilience', 'wisdom']),
(gen_random_uuid(), 'When we are no longer able to change a situation, we are challenged to change ourselves.', 'Viktor Frankl', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'self_improvement', 'resilience']),
(gen_random_uuid(), 'Ultimately, man should not ask what the meaning of his life is, but rather he must recognize that it is he who is asked.', 'Viktor Frankl', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'existence', 'wisdom']),
(gen_random_uuid(), 'Those who have a ''why'' to live, can bear with almost any ''how''.', 'Viktor Frankl', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'resilience', 'inner_strength']),
(gen_random_uuid(), 'Each man is questioned by life; and he can only answer to life by answering for his own life.', 'Viktor Frankl', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'existence', 'wisdom']),
(gen_random_uuid(), 'Love is the only way to grasp another human being in the innermost core of his personality.', 'Viktor Frankl', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'wisdom', 'existence']),
(gen_random_uuid(), 'The last of human freedoms is to choose one''s attitude in any given set of circumstances.', 'Viktor Frankl', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'resilience', 'wisdom']),
(gen_random_uuid(), 'Suffering is an ineradicable part of life, even as fate and death. Without suffering and death human life cannot be complete.', 'Viktor Frankl', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'Man is capable of changing the world for the better if possible, and of changing himself for the better if necessary.', 'Viktor Frankl', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['self_improvement', 'motivation', 'wisdom']),
(gen_random_uuid(), 'Attention is the rarest and purest form of generosity.', 'Simone Weil', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['mindfulness', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Affliction is by its nature inarticulate. The afflicted silently beg to be given the words to express themselves.', 'Simone Weil', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'The intelligent man who is proud of his intelligence is like the condemned man who is proud of his large cell.', 'Simone Weil', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'To be rooted is perhaps the most important and least recognized need of the human soul.', 'Simone Weil', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'existence', 'wisdom']),
(gen_random_uuid(), 'The love of our neighbor in all its fullness simply means being able to say to him: what are you going through?', 'Simone Weil', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'meaning']),
(gen_random_uuid(), 'We must not wish for the disappearance of our troubles but for the grace to transform them.', 'Simone Weil', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'resilience', 'wisdom']),
(gen_random_uuid(), 'The longing to love the beauty of the world in a human being is essentially the longing for the Incarnation.', 'Simone Weil', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'wisdom', 'existence']),
(gen_random_uuid(), 'The danger is not that the soul should doubt whether there is any bread, but that it should persuade itself that it is not hungry.', 'Simone Weil', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'The fully sane person learns to love himself only insofar as he loves others.', 'Erich Fromm', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['self_love', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Selfish persons are incapable of loving others, but they are not capable of loving themselves either.', 'Erich Fromm', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['creativity', 'courage', 'self_improvement']),
(gen_random_uuid(), 'The mother-child relationship is paradoxical and, in a sense, tragic. It requires the most intense love on the mother''s side, yet this very love must help the child grow away from the mother.', 'Erich Fromm', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'Immature love says: I love you because I need you. Mature love says: I need you because I love you.', 'Erich Fromm', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'meaning', 'reflection']),
(gen_random_uuid(), 'There is only one meaning of life: the act of living itself.', 'Erich Fromm', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'Man''s main task in life is to give birth to himself, to become what he potentially is.', 'Erich Fromm', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['self_improvement', 'meaning', 'existence']),
(gen_random_uuid(), 'The art of loving is the art of persistent discipline, patience, concentration and faith.', 'Erich Fromm', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['discipline', 'meaning', 'wisdom']),
(gen_random_uuid(), 'The good life is not one immune to sadness, but one in which suffering contributes to our growth.', 'Iris Murdoch', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['resilience', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Love is the extremely difficult realization that something other than oneself is real.', 'Iris Murdoch', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'meaning', 'existence']),
(gen_random_uuid(), 'We live in a fantasy world, a world of illusion. The great task in life is to find reality.', 'Iris Murdoch', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'One of the things we have to do in order to think well is to be humble; to acknowledge that we don''t know everything.', 'Iris Murdoch', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'curiosity']),
(gen_random_uuid(), 'Art is the most general and refined mode of the communication of ideas.', 'Iris Murdoch', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['creativity', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Hope is a risk that must be run.', 'Gabriel Marcel', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'meaning', 'wisdom']),
(gen_random_uuid(), 'Life is not a problem to be solved, but a reality to be experienced.', 'Gabriel Marcel', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'The being who is the subject of existential philosophy is not the epistemological subject, but the full, concrete human being.', 'Karl Jaspers', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'The first and most fundamental question is: why is there something rather than nothing?', 'Karl Jaspers', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'curiosity', 'wisdom']),
(gen_random_uuid(), 'Man is always something more than what he knows of himself.', 'Karl Jaspers', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'Every human being is human only through his communication with other human beings.', 'Karl Jaspers', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'reflection']),
(gen_random_uuid(), 'The face is the epiphany of the Other.', 'Emmanuel Levinas', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'My being-in-the-world or my place in the sun is the usurpation of spaces belonging to the other man.', 'Emmanuel Levinas', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'To be human is to always be open to being called into question by the other.', 'Emmanuel Levinas', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Doubt is not the opposite of faith; it is one element of faith.', 'Paul Tillich', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'existence', 'meaning']),
(gen_random_uuid(), 'Boredom is rage spread thin.', 'Paul Tillich', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'meaning']),
(gen_random_uuid(), 'Language has created the word loneliness to express the pain of being alone, and the word solitude to express the glory of being alone.', 'Paul Tillich', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'reflection', 'wisdom']),
(gen_random_uuid(), 'The finite mind cannot grasp the infinite, but the finite mind can be grasped by it.', 'Paul Tillich', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Anxiety is the state in which a being is aware of its possible non-being.', 'Paul Tillich', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'reflection', 'wisdom']),
(gen_random_uuid(), 'Freedom is the quality of being that says yes or no to itself.', 'Rollo May', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'inner_strength', 'existence']),
(gen_random_uuid(), 'The clash of ideas is the sound of freedom.', 'Rollo May', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'It is an ironic habit of human beings to run faster when they have lost their way.', 'Rollo May', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Human freedom involves our capacity to pause between the stimulus and response and, in that pause, to choose the one response toward which we wish to throw our weight.', 'Rollo May', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'The body is our general medium for having a world.', 'Maurice Merleau-Ponty', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'We are condemned to meaning.', 'Maurice Merleau-Ponty', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'The world is not what I think, but what I live through.', 'Maurice Merleau-Ponty', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'To live is to be summoned from nowhere to take up a form of existence.', 'Maurice Merleau-Ponty', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'Bourgeois society has made commodity fetishism its own religion.', 'Theodor Adorno', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'The whole is the false.', 'Theodor Adorno', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Wrong life cannot be lived rightly.', 'Theodor Adorno', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'In psychoanalysis nothing is true except the exaggerations.', 'Theodor Adorno', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'curiosity']),
(gen_random_uuid(), 'To write poetry after Auschwitz is barbaric.', 'Theodor Adorno', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Every idea of revolutionizing, transforming, or applying culture presupposes some relation to history.', 'Walter Benjamin', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Contemporaries do not learn from history, they only experience it.', 'Walter Benjamin', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'learning']),
(gen_random_uuid(), 'The tradition of the oppressed teaches us that the state of emergency in which we live is not the exception but the rule.', 'Walter Benjamin', 'philosophy', 'en', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'courage', 'existence']),
(gen_random_uuid(), 'To articulate the past historically does not mean to recognize it the way it really was. It means to seize hold of a memory as it flashes up at a moment of danger.', 'Walter Benjamin', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Not man or men but the struggling, oppressed class itself is the depository of historical knowledge.', 'Walter Benjamin', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'courage', 'existence'])
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, tags) VALUES
(gen_random_uuid(), 'El acto más pequeño en las circunstancias más limitadas lleva la semilla de la misma inmensidad.', 'Hannah Arendt', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'meaning', 'existence']),
(gen_random_uuid(), 'La narración de historias revela el significado sin cometer el error de definirlo.', 'Hannah Arendt', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'meaning', 'creativity']),
(gen_random_uuid(), 'El problema de mentir y engañar es que su eficacia depende completamente de una noción clara de la verdad que el mentiroso desea ocultar.', 'Hannah Arendt', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'El poder corresponde a la capacidad humana no solo de actuar, sino de actuar de manera concertada.', 'Hannah Arendt', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'meaning', 'courage']),
(gen_random_uuid(), 'La triste verdad es que la mayoría del mal es cometido por personas que nunca se decidieron a ser buenas ni malas.', 'Hannah Arendt', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'El perdón es la única reacción que no solo re-actúa, sino que actúa de nuevo e inesperadamente.', 'Hannah Arendt', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Ser libre es, en realidad, comenzar algo nuevo.', 'Hannah Arendt', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'meaning', 'self_improvement']),
(gen_random_uuid(), 'Somos todos iguales, es decir, humanos, de tal modo que nadie es jamás igual a ningún otro ser humano que haya vivido.', 'Hannah Arendt', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'Nadie tiene el derecho de obedecer.', 'Hannah Arendt', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'wisdom', 'existence']),
(gen_random_uuid(), 'El revolucionario más radical se vuelve conservador al día siguiente de la revolución.', 'Hannah Arendt', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'No se nace mujer: se llega a serlo.', 'Simone de Beauvoir', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'Cambia tu vida hoy. No apuestes por el futuro, actúa ahora, sin demora.', 'Simone de Beauvoir', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['motivation', 'discipline', 'self_improvement']),
(gen_random_uuid(), 'Es en el conocimiento de las condiciones genuinas de nuestra vida donde debemos encontrar la fuerza para vivir.', 'Simone de Beauvoir', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'Deseo que toda vida humana sea libertad pura y transparente.', 'Simone de Beauvoir', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'existence', 'wisdom']),
(gen_random_uuid(), 'Querer la propia libertad es también querer la libertad de los demás.', 'Simone de Beauvoir', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'meaning', 'wisdom']),
(gen_random_uuid(), 'Toda opresión crea un estado de guerra.', 'Simone de Beauvoir', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'wisdom', 'existence']),
(gen_random_uuid(), 'Todo está resuelto, excepto cómo vivir.', 'Simone de Beauvoir', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'Entre los veinte y los cuarenta años estamos en el proceso de descubrir quiénes somos.', 'Simone de Beauvoir', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['reflection', 'self_improvement', 'existence']),
(gen_random_uuid(), 'Entre el estímulo y la respuesta hay un espacio. En ese espacio reside nuestro poder de elegir.', 'Viktor Frankl', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'La vida no se vuelve insoportable por las circunstancias, sino solo por la falta de sentido y propósito.', 'Viktor Frankl', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'resilience', 'wisdom']),
(gen_random_uuid(), 'Cuando ya no podemos cambiar una situación, nos enfrentamos al desafío de cambiarnos a nosotros mismos.', 'Viktor Frankl', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'self_improvement', 'resilience']),
(gen_random_uuid(), 'El hombre no debería preguntarse cuál es el significado de su vida, sino que debe reconocer que es él quien debe responder.', 'Viktor Frankl', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'existence', 'wisdom']),
(gen_random_uuid(), 'Los que tienen un ''por qué'' para vivir pueden soportar casi cualquier ''cómo''.', 'Viktor Frankl', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'resilience', 'inner_strength']),
(gen_random_uuid(), 'La última de las libertades humanas es elegir la propia actitud ante cualquier conjunto de circunstancias.', 'Viktor Frankl', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'resilience', 'wisdom']),
(gen_random_uuid(), 'El sufrimiento es una parte ineradicable de la vida, al igual que el destino y la muerte.', 'Viktor Frankl', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'El hombre es capaz de cambiar el mundo a mejor si es posible, y de cambiarse a sí mismo a mejor si es necesario.', 'Viktor Frankl', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['self_improvement', 'motivation', 'wisdom']),
(gen_random_uuid(), 'La atención es la forma más rara y pura de generosidad.', 'Simone Weil', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['mindfulness', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Estar enraizados es quizás la necesidad más importante y menos reconocida del alma humana.', 'Simone Weil', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'existence', 'wisdom']),
(gen_random_uuid(), 'El amor al prójimo en toda su plenitud significa poder decirle: ¿qué estás pasando?', 'Simone Weil', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'meaning']),
(gen_random_uuid(), 'No debemos desear que desaparezcan nuestros problemas, sino tener la gracia de transformarlos.', 'Simone Weil', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'resilience', 'wisdom']),
(gen_random_uuid(), 'La aflicción es, por naturaleza, inarticul able. Los afligidos ruegan en silencio que se les den las palabras para expresarse.', 'Simone Weil', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'El hombre plenamente cuerdo aprende a amarse a sí mismo solo en la medida en que ama a los demás.', 'Erich Fromm', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['self_love', 'wisdom', 'meaning']),
(gen_random_uuid(), 'La creatividad requiere el coraje de soltar las certezas.', 'Erich Fromm', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['creativity', 'courage', 'self_improvement']),
(gen_random_uuid(), 'El amor inmaduro dice: te amo porque te necesito. El amor maduro dice: te necesito porque te amo.', 'Erich Fromm', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'meaning', 'reflection']),
(gen_random_uuid(), 'Solo hay un significado de la vida: el acto de vivir en sí mismo.', 'Erich Fromm', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'La tarea principal del hombre en la vida es darse a luz a sí mismo, convertirse en lo que potencialmente es.', 'Erich Fromm', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['self_improvement', 'meaning', 'existence']),
(gen_random_uuid(), 'El arte de amar es el arte de la disciplina persistente, la paciencia, la concentración y la fe.', 'Erich Fromm', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['discipline', 'meaning', 'wisdom']),
(gen_random_uuid(), 'La buena vida no es aquella inmune a la tristeza, sino aquella en la que el sufrimiento contribuye a nuestro crecimiento.', 'Iris Murdoch', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['resilience', 'wisdom', 'meaning']),
(gen_random_uuid(), 'El amor es la realización extraordinariamente difícil de que algo distinto de uno mismo es real.', 'Iris Murdoch', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'meaning', 'existence']),
(gen_random_uuid(), 'Vivimos en un mundo de fantasía, un mundo de ilusión. La gran tarea en la vida es encontrar la realidad.', 'Iris Murdoch', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Para pensar bien hay que ser humilde; reconocer que no lo sabemos todo.', 'Iris Murdoch', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'curiosity']),
(gen_random_uuid(), 'El arte es el modo más general y refinado de la comunicación de ideas.', 'Iris Murdoch', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['creativity', 'wisdom', 'meaning']),
(gen_random_uuid(), 'La esperanza es un riesgo que hay que correr.', 'Gabriel Marcel', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'meaning', 'wisdom']),
(gen_random_uuid(), 'La vida no es un problema que resolver, sino una realidad que vivir.', 'Gabriel Marcel', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'La primera pregunta y la más fundamental es: ¿por qué hay algo en lugar de nada?', 'Karl Jaspers', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'curiosity', 'wisdom']),
(gen_random_uuid(), 'El hombre es siempre algo más que lo que sabe de sí mismo.', 'Karl Jaspers', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'Todo ser humano es humano solo a través de su comunicación con otros seres humanos.', 'Karl Jaspers', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'reflection']),
(gen_random_uuid(), 'El ser que es sujeto de la filosofía existencial no es el sujeto epistemológico, sino el ser humano pleno y concreto.', 'Karl Jaspers', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'El rostro es la epifanía del Otro.', 'Emmanuel Levinas', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'Ser humano es estar siempre abierto a ser cuestionado por el otro.', 'Emmanuel Levinas', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Mi ser-en-el-mundo o mi lugar bajo el sol es la usurpación de los espacios que pertenecen al otro.', 'Emmanuel Levinas', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'El coraje de ser tiene sus raíces en el Dios que aparece cuando Dios ha desaparecido en la angustia de la duda.', 'Paul Tillich', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'existence', 'meaning']),
(gen_random_uuid(), 'El primer deber del amor es escuchar.', 'Paul Tillich', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'meaning']),
(gen_random_uuid(), 'El lenguaje ha creado la palabra soledad para expresar el dolor de estar solo, y la palabra recogimiento para expresar la gloria de estar solo.', 'Paul Tillich', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'reflection', 'wisdom']),
(gen_random_uuid(), 'El que arriesga y fracasa puede ser perdonado. El que nunca arriesga y nunca fracasa es un fracaso en todo su ser.', 'Paul Tillich', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'wisdom', 'meaning']),
(gen_random_uuid(), 'La ansiedad es el estado en que un ser es consciente de su posible no-ser.', 'Paul Tillich', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'reflection', 'wisdom']),
(gen_random_uuid(), 'La libertad es la cualidad del ser que dice sí o no a sí mismo.', 'Rollo May', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'inner_strength', 'existence']),
(gen_random_uuid(), 'Lo opuesto al coraje en nuestra sociedad no es la cobardía, sino la conformidad.', 'Rollo May', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'Es un hábito irónico de los seres humanos correr más rápido cuando han perdido el rumbo.', 'Rollo May', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'La libertad humana implica nuestra capacidad de hacer una pausa entre el estímulo y la respuesta y, en esa pausa, elegir.', 'Rollo May', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['inner_strength', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'El cuerpo es nuestro medio general de tener un mundo.', 'Maurice Merleau-Ponty', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Estamos condenados al significado.', 'Maurice Merleau-Ponty', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'El mundo no es lo que pienso, sino lo que vivo.', 'Maurice Merleau-Ponty', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Vivir es ser convocado desde ningún lugar para asumir una forma de existencia.', 'Maurice Merleau-Ponty', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'meaning', 'wisdom']),
(gen_random_uuid(), 'Una vida equivocada no puede vivirse correctamente.', 'Theodor Adorno', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'El todo es lo falso.', 'Theodor Adorno', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'En psicoanálisis nada es verdadero salvo las exageraciones.', 'Theodor Adorno', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'curiosity']),
(gen_random_uuid(), 'Escribir poesía después de Auschwitz es un acto de barbarie.', 'Theodor Adorno', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'meaning']),
(gen_random_uuid(), 'La sociedad burguesa ha hecho del fetichismo de las mercancías su propia religión.', 'Theodor Adorno', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Los contemporáneos no aprenden de la historia; solo la experimentan.', 'Walter Benjamin', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'learning']),
(gen_random_uuid(), 'La tradición de los oprimidos nos enseña que el estado de excepción en el que vivimos es la regla, no la excepción.', 'Walter Benjamin', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'courage', 'existence']),
(gen_random_uuid(), 'Articular el pasado históricamente no significa reconocerlo tal como fue. Significa apoderarse de un recuerdo tal como relampaguea en un instante de peligro.', 'Walter Benjamin', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'No el hombre o los hombres, sino la clase oprimida en lucha es depositaria del conocimiento histórico.', 'Walter Benjamin', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'courage', 'existence']),
(gen_random_uuid(), 'Toda idea de transformar la cultura presupone alguna relación con la historia.', 'Walter Benjamin', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence'])
