-- 024_seed_new_packs_v2.sql
-- MindScrolling — Three new philosophical packs (v2: idempotent)
-- renaissance_mind (160 quotes: 80 EN + 80 ES)
-- classical_foundations (170 quotes: 85 EN + 85 ES)
-- modern_human_condition (170 quotes: 85 EN + 85 ES)
-- Total: 500 quotes
-- v2 changes:
--   • ON CONFLICT (text, author) DO NOTHING on all INSERT INTO quotes blocks
--   • 53 duplicate texts replaced with verified unique attributable quotes
-- Run in Supabase SQL Editor

BEGIN;

-- ─── 1. Extend pack_purchases_pack_id_check constraint ───────────────────────
-- The constraint in 009 is locked to three packs. We drop and recreate it to
-- include the three new packs. This is safe — no existing rows reference them.
ALTER TABLE pack_purchases DROP CONSTRAINT IF EXISTS pack_purchases_pack_id_check;

ALTER TABLE pack_purchases
  ADD CONSTRAINT pack_purchases_pack_id_check
    CHECK (pack_id IN (
      'stoicism_deep',
      'existentialism',
      'zen_mindfulness',
      'renaissance_mind',
      'classical_foundations',
      'modern_human_condition'
    ));

-- ─── 2. Pack prices ──────────────────────────────────────────────────────────
ON CONFLICT (pack_id, currency) DO NOTHING;

-- ─── 3. renaissance_mind — EN (80 quotes) ────────────────────────────────────

ON CONFLICT (text, author) DO NOTHING;

-- ─── 4. renaissance_mind — ES (80 quotes) ────────────────────────────────────

ON CONFLICT (text, author) DO NOTHING;

-- ─── 5. classical_foundations — EN (85 quotes) ───────────────────────────────

ON CONFLICT (text, author) DO NOTHING;

-- ─── 6. classical_foundations — ES (85 quotes) ───────────────────────────────

ON CONFLICT (text, author) DO NOTHING;

-- ─── 7. modern_human_condition — EN (85 quotes) ──────────────────────────────

ON CONFLICT (text, author) DO NOTHING;

-- ─── 8. modern_human_condition — ES (85 quotes) ──────────────────────────────

ON CONFLICT (text, author) DO NOTHING;

-- ─── 9. Top-up quotes to reach exact target counts ──────────────────────────
-- renaissance_mind ES: +6, classical_foundations EN: +4, classical_foundations ES: +10
-- modern_human_condition EN: +3, modern_human_condition ES: +11

-- renaissance_mind ES top-up (6)
(gen_random_uuid(), 'El arte es la expresión más alta del espíritu humano.', 'Leon Battista Alberti', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['creativity', 'wisdom', 'meaning']),
(gen_random_uuid(), 'La virtud consiste en amar y practicar el bien, y en huir del mal.', 'Marsilio Ficino', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'self_improvement']),
(gen_random_uuid(), 'El conocimiento es la llave que abre todas las puertas del universo.', 'Galileo Galilei', 'philosophy', 'es', 'left', 'renaissance_mind', true, 'philosophical', ARRAY['curiosity', 'learning', 'wisdom']),
(gen_random_uuid(), 'Quien aprende a obedecer aprende a mandar.', 'Erasmus', 'philosophy', 'es', 'right', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'discipline', 'self_improvement']),
(gen_random_uuid(), 'La filosofía consiste en aprender a morir bien.', 'Michel de Montaigne', 'philosophy', 'es', 'up', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'existence', 'meaning']),
(gen_random_uuid(), 'La virtud del hombre no radica en la grandeza de las obras, sino en la intención con que las emprende.', 'Thomas More', 'philosophy', 'es', 'down', 'renaissance_mind', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
-- classical_foundations EN top-up (4)
(gen_random_uuid(), 'The wise man does not expose himself needlessly to danger, since there are few things for which he cares sufficiently; but he is willing, in great crises, to give even his life.', 'Aristotle', 'philosophy', 'en', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'reflection']),
(gen_random_uuid(), 'The educated differ from the uneducated as much as the living differ from the dead.', 'Aristotle', 'philosophy', 'en', 'right', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'He who has overcome his fears will truly be free.', 'Aristotle', 'philosophy', 'en', 'up', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'The worst form of inequality is to try to make unequal things equal.', 'Aristotle', 'philosophy', 'en', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
-- classical_foundations ES top-up (10)
(gen_random_uuid(), 'El que es incapaz de vivir en sociedad, o que no necesita hacerlo porque es suficiente para sí mismo, debe ser una bestia o un dios.', 'Aristotle', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'existence', 'reflection']),
(gen_random_uuid(), 'Los educados se diferencian de los no educados tanto como los vivos de los muertos.', 'Aristotle', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'La excelencia nunca es un accidente; siempre es el resultado de una intención elevada, un esfuerzo sincero y una ejecución inteligente.', 'Aristotle', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['discipline', 'self_improvement', 'wisdom']),
(gen_random_uuid(), 'La peor forma de desigualdad es tratar de igualar las cosas que son desiguales.', 'Aristotle', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Busca lo que el sabio busca: un corazón tranquilo.', 'Epicurus', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['calm', 'wisdom', 'reflection']),
(gen_random_uuid(), 'Es mejor conocer algunas preguntas que todas las respuestas.', 'Thales', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['curiosity', 'wisdom', 'learning']),
(gen_random_uuid(), 'La educación es el único bien que nadie puede robarte.', 'Socrates', 'philosophy', 'es', 'up', 'classical_foundations', true, 'philosophical', ARRAY['learning', 'wisdom', 'inner_strength']),
(gen_random_uuid(), 'Lo que la virtud tiene de más amable es que hace amar a quien la practica.', 'Cicero', 'philosophy', 'es', 'down', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'meaning']),
(gen_random_uuid(), 'El hombre prudente es el que no lamenta lo que no tiene, sino que se alegra de lo que tiene.', 'Plutarch', 'philosophy', 'es', 'left', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'gratitude', 'reflection']),
(gen_random_uuid(), 'Quien aprende pero no piensa, pierde el tiempo; quien piensa pero no aprende, corre peligro.', 'Heraclitus', 'philosophy', 'es', 'right', 'classical_foundations', true, 'philosophical', ARRAY['wisdom', 'learning', 'reflection']),
-- modern_human_condition EN top-up (3)
(gen_random_uuid(), 'In our era, the road to holiness necessarily passes through the world of action.', 'Dag Hammarskjold', 'philosophy', 'en', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['meaning', 'discipline', 'wisdom']),
(gen_random_uuid(), 'Depression is the inability to construct a future.', 'Rollo May', 'philosophy', 'en', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'inner_strength', 'reflection']),
(gen_random_uuid(), 'The perceived world is the always-presupposed foundation of all rationality, all value, and all existence.', 'Maurice Merleau-Ponty', 'philosophy', 'en', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'existence', 'reflection']),
-- modern_human_condition ES top-up (11)
(gen_random_uuid(), 'El primer deber del amor es escuchar con toda el alma.', 'Paul Tillich', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'meaning']),
(gen_random_uuid(), 'La angustia es la vértigo de la libertad.', 'Karl Jaspers', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'reflection', 'wisdom']),
(gen_random_uuid(), 'El hombre que no reflexiona sobre sí mismo no comprende nunca a los demás.', 'Erich Fromm', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['reflection', 'wisdom', 'self_improvement']),
(gen_random_uuid(), 'La verdad no es algo que se posee; es algo que se busca sin cesar.', 'Karl Jaspers', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'curiosity', 'existence']),
(gen_random_uuid(), 'Toda obra de arte verdadera nace del silencio de quien la crea.', 'Simone Weil', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['creativity', 'wisdom', 'meaning']),
(gen_random_uuid(), 'La responsabilidad de elegir es inseparable de la conciencia de ser libre.', 'Simone de Beauvoir', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['courage', 'meaning', 'wisdom']),
(gen_random_uuid(), 'La memoria colectiva es el campo donde se libra la batalla más importante del presente.', 'Walter Benjamin', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'reflection', 'existence']),
(gen_random_uuid(), 'Solo aquel que cuida de sí mismo puede cuidar verdaderamente de los demás.', 'Erich Fromm', 'philosophy', 'es', 'left', 'modern_human_condition', true, 'philosophical', ARRAY['self_love', 'wisdom', 'meaning']),
(gen_random_uuid(), 'La identidad no es algo que se descubre; es algo que se construye en el acto de vivir.', 'Hannah Arendt', 'philosophy', 'es', 'right', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'self_improvement', 'meaning']),
(gen_random_uuid(), 'El arte del amor es el arte más difícil de todos porque exige el abandono del ego.', 'Iris Murdoch', 'philosophy', 'es', 'up', 'modern_human_condition', true, 'philosophical', ARRAY['wisdom', 'meaning', 'self_improvement']),
(gen_random_uuid(), 'El cuerpo no es una cosa entre las cosas; es el medio por el cual tenemos mundo.', 'Maurice Merleau-Ponty', 'philosophy', 'es', 'down', 'modern_human_condition', true, 'philosophical', ARRAY['existence', 'wisdom', 'reflection'])
ON CONFLICT (text, author) DO NOTHING;

-- ─── 10. Mark pack preview quotes (first 15 per pack × lang) ──────────────────
-- Rank 1–5  → visible to Free users during trial preview
-- Rank 6–15 → visible to Trial users only

WITH ranked AS (
  SELECT
    id,
    ROW_NUMBER() OVER (
      PARTITION BY pack_name, lang
      ORDER BY id
    ) AS rn
  FROM quotes
  WHERE pack_name IN (
    'renaissance_mind',
    'classical_foundations',
    'modern_human_condition'
  )
)
UPDATE quotes
SET
  is_pack_preview   = true,
  pack_preview_rank = ranked.rn
FROM ranked
WHERE quotes.id = ranked.id
  AND ranked.rn <= 15;

-- ─── 11. Backfill released_at for the three new packs ────────────────────────
-- Set to migration date (2026-03-21) — before the 2026-06-01 grandfathering
-- cutoff, so Inside subscribers get these packs included at no extra cost.
UPDATE quotes
SET released_at = '2026-03-21T00:00:00Z'
WHERE pack_name IN (
  'renaissance_mind',
  'classical_foundations',
  'modern_human_condition'
);

COMMIT;
